import pytest
import requests

def test_create_cii_medication_request_without_schedule_verification_returns_403(
    prescriber_token_no_schedule, base_url
):
    headers = {"Authorization": f"Bearer {prescriber_token_no_schedule}",
               "Content-Type": "application/fhir+json"}
    payload = {
        "resourceType": "MedicationRequest",
        "status": "active",
        "intent": "order",
        "subject": {"reference": "Patient/test-patient-1"},
        "medicationCodeableConcept": {
            "coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                        "code": "7804", "display": "Oxycodone 5mg"}],
            "extension": [{
                "url": "http://fhir-lite.local/dea-schedule",
                "valueCode": "CII"
            }]
        },
        "requester": {"reference": "Practitioner/test-prescriber-1"}
    }
    resp = requests.post(f"{base_url}/MedicationRequest",
                         json=payload, headers=headers)
    assert resp.status_code == 403
    body = resp.json()
    assert "schedule" in str(body).lower() or "verification" in str(body).lower()

    audit_resp = requests.get(
        f"{base_url}/AuditEvent",
        params={"outcome": "8", "action": "C"},
        headers={"Authorization": f"Bearer {prescriber_token_no_schedule}"}
    )
    assert audit_resp.status_code == 200
    assert len(audit_resp.json().get("entry", [])) >= 1

import pytest
import requests

def test_create_cii_medication_request_with_schedule_verification_succeeds(
    prescriber_token_with_schedule, base_url, cleanup_resource
):
    headers = {"Authorization": f"Bearer {prescriber_token_with_schedule}",
               "Content-Type": "application/fhir+json"}
    payload = {
        "resourceType": "MedicationRequest",
        "status": "active",
        "intent": "order",
        "subject": {"reference": "Patient/test-patient-1"},
        "medicationCodeableConcept": {
            "coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                        "code": "7804", "display": "Oxycodone 5mg"}],
            "extension": [{
                "url": "http://fhir-lite.local/dea-schedule",
                "valueCode": "CII"
            }]
        },
        "requester": {"reference": "Practitioner/test-prescriber-1"}
    }
    resp = requests.post(f"{base_url}/MedicationRequest",
                         json=payload, headers=headers)
    assert resp.status_code == 201
    resource_id = resp.json()["id"]
    cleanup_resource(f"{base_url}/MedicationRequest/{resource_id}", headers)

    audit_resp = requests.get(
        f"{base_url}/AuditEvent",
        params={"entity": f"MedicationRequest/{resource_id}", "outcome": "0"},
        headers=headers
    )
    assert audit_resp.status_code == 200
    entries = audit_resp.json().get("entry", [])
    assert any(e["resource"]["action"] == "C" for e in entries)
